        "# ============================================================\n",
        "# STEP 6: CHI-SQUARE TEST + CRAMÉR'S V\n",
        "# File: step6_chi_square.py\n",
        "# ============================================================\n",
        "\n",
        "import pandas as pd\n",
        "import numpy as np\n",
        "from scipy import stats\n",
        "import matplotlib.pyplot as plt\n",
        "import seaborn as sns\n",
        "\n",
        "merged = pd.read_csv('merged_state_data.csv')\n",
        "\n",
        "print(\"=\"*70)\n",
        "print(\"CHI-SQUARE TEST: AQI Group vs Binary Child Health Outcomes\")\n",
        "print(\"=\"*70)\n",
        "\n",
        "binary_health = ['ARI_high', 'Stunting_high', 'Anaemia_high', 'Underweight_high']\n",
        "chi_results = []\n",
        "\n",
        "for var in binary_health:\n",
        "    ct = pd.crosstab(merged['AQI_Group'], merged[var])\n",
        "    print(f\"\\nContingency Table: AQI Group vs {var}\")\n",
        "    print(ct)\n",
        "    chi2, p, dof, expected = stats.chi2_contingency(ct)\n",
        "    n = ct.values.sum()\n",
        "    cramers_v = np.sqrt(chi2 / (n * (min(ct.shape) - 1)))\n",
        "    sig = '***' if p<0.001 else ('**' if p<0.01 else ('*' if p<0.05 else 'ns'))\n",
        "    print(f\"  chi2={chi2:.3f}  df={dof}  p={p:.4f} {sig}  Cramér's V={cramers_v:.3f}\")\n",
        "    chi_results.append({\n",
        "        'Health_Var': var, 'Chi2': round(chi2,3), 'df': dof,\n",
        "        'p_value': round(p,4), \"Cramer_V\": round(cramers_v,3), 'Significant': sig\n",
        "    })\n",
        "\n",
        "pd.DataFrame(chi_results).to_csv('table5_chi_square.csv', index=False)\n",
        "print(\"\\n✅ Saved: table5_chi_square.csv\")\n",
        "\n",
        "# ── Stacked bar charts ────────────────────────────────────────\n",
        "fig, axes = plt.subplots(1, 4, figsize=(18, 5))\n",
        "labels = ['ARI', 'Stunting', 'Anaemia', 'Underweight']\n",
        "\n",
        "for ax, var, label in zip(axes, binary_health, labels):\n",
        "    ct = pd.crosstab(merged['AQI_Group'], merged[var], normalize='index') * 100\n",
        "    ct.plot(kind='bar', stacked=True, ax=ax,\n",
        "            color=['#98df8a', '#d62728'], width=0.5)\n",
        "    ax.set_title(f'{label}\\n(High=1 if ≥ median)', fontsize=10, fontweight='bold')\n",
        "    ax.set_xlabel('AQI Group')\n",
        "    ax.set_ylabel('Proportion (%)')\n",
        "    ax.set_xticklabels(ax.get_xticklabels(), rotation=0)\n",
        "    ax.legend(['Below median (0)', 'Above median (1)'], fontsize=7)\n",
        "\n",
        "plt.suptitle(\"Chi-Square: AQI Group vs Binary Child Health Outcomes\",\n",
        "             fontsize=12, fontweight='bold')\n",
        "plt.tight_layout()\n",
        "plt.savefig('fig8_chi_square_stacked_bar.png', bbox_inches='tight')\n",
        "plt.show()\n",
        "print(\"✅ Saved: fig8_chi_square_stacked_bar.png\")"
