        "# ============================================================\n",
        "# STEP 7: HIGH-RISK STATE IDENTIFICATION\n",
        "# File: step7_priority_states.py\n",
        "# ============================================================\n",
        "\n",
        "import pandas as pd\n",
        "import numpy as np\n",
        "import matplotlib.pyplot as plt\n",
        "import matplotlib.patches as mpatches\n",
        "\n",
        "merged = pd.read_csv('merged_state_data.csv')\n",
        "\n",
        "# Composite child health index (average of 4 normalised indicators)\n",
        "from sklearn.preprocessing import MinMaxScaler\n",
        "scaler = MinMaxScaler()\n",
        "health_cols = ['ARI_pct', 'Stunting_pct', 'Underweight_pct', 'Anaemia_pct']\n",
        "merged['Health_Index'] = scaler.fit_transform(merged[health_cols]).mean(axis=1)\n",
        "\n",
        "# Normalise AQI too\n",
        "merged['AQI_norm'] = scaler.fit_transform(merged[['mean_AQI']])\n",
        "\n",
        "# Quadrant classification\n",
        "aqi_med    = merged['AQI_norm'].median()\n",
        "health_med = merged['Health_Index'].median()\n",
        "\n",
        "def quadrant(row):\n",
        "    if row['AQI_norm'] >= aqi_med and row['Health_Index'] >= health_med:\n",
        "        return 'HIGH RISK\\n(High AQI + Poor Health)'\n",
        "    elif row['AQI_norm'] < aqi_med and row['Health_Index'] >= health_med:\n",
        "        return 'Health Concern\\n(Low AQI + Poor Health)'\n",
        "    elif row['AQI_norm'] >= aqi_med and row['Health_Index'] < health_med:\n",
        "        return 'Air Quality Concern\\n(High AQI + Good Health)'\n",
        "    else:\n",
        "        return 'Favourable\\n(Low AQI + Good Health)'\n",
        "\n",
        "merged['Quadrant'] = merged.apply(quadrant, axis=1)\n",
        "\n",
        "colors = {\n",
        "    'HIGH RISK\\n(High AQI + Poor Health)':       '#d62728',\n",
        "    'Health Concern\\n(Low AQI + Poor Health)':    '#ff7f0e',\n",
        "    'Air Quality Concern\\n(High AQI + Good Health)': '#1f77b4',\n",
        "    'Favourable\\n(Low AQI + Good Health)':         '#2ca02c',\n",
        "}\n",
        "\n",
        "fig, ax = plt.subplots(figsize=(12, 8))\n",
        "for q, grp in merged.groupby('Quadrant'):\n",
        "    ax.scatter(grp['AQI_norm'], grp['Health_Index'],\n",
        "               s=100, color=colors.get(q,'gray'), label=q, edgecolors='k', alpha=0.8)\n",
        "    for _, row in grp.iterrows():\n",
        "        ax.annotate(row['State'], (row['AQI_norm'], row['Health_Index']),\n",
        "                    fontsize=7, ha='left', va='bottom')\n",
        "\n",
        "ax.axvline(x=aqi_med, color='gray', linestyle='--', alpha=0.5)\n",
        "ax.axhline(y=health_med, color='gray', linestyle='--', alpha=0.5)\n",
        "ax.set_xlabel('Normalised Mean AQI', fontsize=12)\n",
        "ax.set_ylabel('Composite Child Health Risk Index', fontsize=12)\n",
        "ax.set_title('Quadrant Analysis: Air Quality vs Child Health Risk by State',\n",
        "             fontsize=13, fontweight='bold')\n",
        "ax.legend(loc='upper left', fontsize=8)\n",
        "plt.tight_layout()\n",
        "plt.savefig('fig9_quadrant_priority.png', bbox_inches='tight')\n",
        "plt.show()\n",
        "print(\"✅ Saved: fig9_quadrant_priority.png\")\n",
        "\n",
        "# High risk states\n",
        "high_risk = merged[merged['Quadrant'].str.startswith('HIGH')]\n",
        "print(\"\\n🚨 HIGH RISK STATES (High AQI + Poor Child Health):\")\n",
        "print(high_risk[['State','mean_AQI','ARI_pct','Stunting_pct','Anaemia_pct','Underweight_pct']].to_string())\n",
        "high_risk.to_csv('table6_high_risk_states.csv', index=False)\n",
        "print(\"\\n✅ Saved: table6_high_risk_states.csv\")"
